window.__LIBQ=window.__LIBQ||{};window.__LIBQ["the-gioi-hoan-my"]=window.__LIBQ["the-gioi-hoan-my"]||{};window.__LIBQ["the-gioi-hoan-my"]["q04"]=window.__LIBQ["the-gioi-hoan-my"]["q04"]||{};window.__LIBQ["the-gioi-hoan-my"]["q04"]["techniques"]={"updatedAt":"2026-07-21","count":108,"techniques":[{"id":"dai-tran-phong-toa-san-nho","name":"Đại trận phong tỏa sân nhỏ","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"","soHuu":[],"blurb":"Trận pháp phong tỏa sân nhỏ trong khách sạn Hổ Môn, ngăn người bên trong liên lạc với bên ngoài.","detail":"Nhiều trận kỳ phát sáng trói buộc thiên địa và đan dệt phù văn thành màn sáng cách ly sân nhỏ. Khi các trận kỳ trong sân bị lấy đi, trận pháp tự động mở ra.","nguon":["@c0301"]},{"id":"bat-hung-kiem-tran","name":"Bát Hung kiếm trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Truyền thừa Thượng Cổ","hePhai":"Vũ tộc","soHuu":["Vũ tộc","Thạch Hạo"],"blurb":"Kiếm trận phối hợp tám phi kiếm với kiếm quyết và thần chú, khiến sức mạnh của các thanh kiếm nối tiếp rồi chồng chất lên nhau.","detail":"Bản kiếm trận đang được Vũ tộc sử dụng gồm tám phi kiếm làm từ phù cốt di chủng. Bản chân chính thời Thượng Cổ cần nguyên thủy phù cốt của tám loại chim thần và hung thú thuần huyết trưởng thành, từng được xưng là sát trận có thể giết Thánh chém Ma.","thuocTinh":"Kiếm trận tám phi kiếm","nguonGoc":"Truyền thừa từ thời Thượng Cổ","uyLuc":"Thế kiếm liên tiếp chồng chất thành biển kiếm; bản chân chính được xưng có thể giết Thánh chém Ma.","dacDiem":"Cần phối hợp tám phi kiếm, một tổ kiếm quyết và thần chú.","congNang":["Liên kết sức mạnh của tám phi kiếm, khiến kiếm quang và uy lực tầng tầng chồng chất."],"capNhatToi":"@c0302","tabs":{"tienTrinh":[{"chuong":"@c0302","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Hé lộ cấu tạo kiếm trận","text":"Bát Hung kiếm trận được xác nhận là sát trận kết hợp tám phi kiếm với kiếm quyết và thần chú.","anchor":"sau đó phối hợp với một tổ kiếm quyết cùng với thần chú tạo thành kiếm trận"}]},"nguon":["@c0302"]},{"id":"dai-tran-tran-ky-vu-vuong-phu","name":"Đại trận trận kỳ Vũ Vương phủ","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"Vũ tộc","soHuu":["Vũ tộc"],"blurb":"Trận pháp phòng thủ của Vũ Vương phủ, được dựng bằng hơn mười đại kỳ để phong tỏa và công kích kẻ xâm nhập.","detail":"Khi triển khai, các đại kỳ phóng lớn lên tầng mây, sinh ra sương mù và sấm chớp. Thạch Hạo trong trạng thái dung hợp Bất Diệt Kim Thân đã đánh nát phù văn, bẻ gãy hơn mười đại kỳ và phá tan trận pháp bằng một chưởng.","nguon":["@c0303"]},{"id":"vu-dao-cuu-trung-thien","name":"Vũ Đạo Cửu Trùng Thiên","cn":"","loai":"than-thong","loaiLabel":"Thần thông hợp kích","phamCap":"","hePhai":"Vũ tộc","soHuu":["Vũ tộc"],"blurb":"Thần thông hợp kích quy mô lớn của Vũ tộc, cần nhiều người liên thủ thi triển và gồm chín đợt bộc phát có uy lực tăng dần.","detail":"Khi thi triển, thần thông tạo ra màn mưa, lực nước và hoa sen vừa công vừa thủ, đồng thời phong tỏa các phương vị quanh mục tiêu. Hoa sen nở qua chín lần, mỗi lần mạnh hơn lần trước; đòn tối hậu được truyền tụng là có liên quan tới Thần Linh.","nguon":["@c0304"]},{"id":"than-the-thanh-linh","name":"Thân thể thành Linh","cn":"","loai":"khac","loaiLabel":"Năng lực Hóa Linh cảnh","phamCap":"Hóa Linh viên mãn","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Năng lực đạt được khi Thạch Hạo tu luyện Hóa Linh cảnh tới viên mãn, cho phép hóa giải tinh khí của người khác để bản thân sử dụng.","detail":"Thạch Hạo vận dụng trạng thái này cùng Bảo thuật Côn Bằng để hóa giải và hấp thu thần năng từ Vũ Đạo Cửu Trùng Thiên, chuyển lực lượng trong đòn công kích của đối phương thành tinh khí tích tụ trong cơ thể mình.","nguon":["@c0304"]},{"id":"bao-thuat-vu-toc","name":"Bảo thuật Vũ tộc","cn":"","loai":"than-thong","loaiLabel":"Bảo thuật","phamCap":"Chiêu cấm kỵ ở đóa sen thứ chín","hePhai":"Vũ tộc","soHuu":[],"blurb":"Bảo thuật mưa và hoa sen của Vũ tộc, thông thường có thể tạo ra tám đóa sen. Đóa thứ chín là chiêu cấm kỵ, có khả năng triệu tới hình chiếu cùng một tia uy năng của Vũ Thần.","detail":"Khi Vũ Thần cảm ứng được lời triệu gọi của hậu nhân, đóa sen thứ chín có thể tự ngưng tụ và hiển hóa hình chiếu của ông từ nơi xa xôi. Hình chiếu xuất hiện giữa sương mù, nhật nguyệt và tinh thần, mang uy thế đủ khiến Thạch Hạo nhiều lần trọng thương.","nguon":["@c0305"]},{"id":"than-thong-cam-ky-trieu-goi-vu-than","name":"Thần thông cấm kỵ triệu gọi Vũ Thần","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cấm kỵ","hePhai":"Vũ tộc","soHuu":["Vũ tộc"],"blurb":"Thần thông do nhiều người Vũ tộc liên thủ thi triển để triệu gọi hình chiếu Vũ Thần.","detail":"Hình chiếu được triệu gọi có uy lực đe dọa tính mạng Thạch Hạo, nhưng trong lần thi triển tại phủ Vũ tộc đã mất ổn định, rạn nứt rồi giải thể trước khi phát huy thần uy cuối cùng.","nguon":["@c0306"]},{"id":"co-tran-vu-toc","name":"Cổ trận Vũ tộc","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Cổ trận","hePhai":"Vũ tộc","soHuu":["Vũ tộc"],"blurb":"Trận pháp phòng thủ chôn trong phế tích Vũ tộc, kết hợp tấm biển đồng thau, bốn cốt đăng và ba mươi sáu chiến mâu để vây khốn, công kích mục tiêu.","detail":"Cổ trận được Vũ tộc bố trí sẵn và chỉ vận dụng trong tình huống đặc biệt. Khi kích hoạt, tấm biển đồng thau đóng vai trò trận đồ, bốn cốt đăng tạo lửa xanh biếc vây luyện ở trung tâm, còn ba mươi sáu chiến mâu liên tục xung kích; trận pháp bị Thạch Hạo phá giải bằng kiếm gãy, Đào Uyển và kiếm trận Bát Hung.","nguon":["@c0307"]},{"id":"dai-tran-vu-toc","name":"Đại trận Vũ tộc","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"Vũ tộc","soHuu":["Vũ tộc"],"blurb":"Đại trận bảo vệ Vũ Vương phủ, được mở ra để đối phó Thạch Hạo.","detail":"Đại trận tạo thành sát cục trong Vũ Vương phủ. Thạch Hạo chủ động rút lui, không bước vào phạm vi trận pháp; người Vũ tộc về sau phải rời khỏi đại trận mới có thể truy kích nó.","nguon":["@c0308"]},{"id":"tu-ly-can-khon","name":"Tụ lý càn khôn","cn":"","loai":"than-thong","loaiLabel":"Đại thần thông","phamCap":"Đại thần thông","hePhai":"Nhân tộc","soHuu":["Thạch Tử Đằng"],"blurb":"Đại thần thông biến tay áo thành một không gian tự thành một giới, có thể cưỡng ép thu đối thủ vào trong.","detail":"Tụ lý càn khôn do một vị thần nhân Nhân tộc sáng tạo, không thuộc truyền thừa của hồ Ma Linh. Thạch Tử Đằng dùng thần thông này nhằm thu và nhanh chóng giết Thạch Hạo, nhưng thế thu giữ bị Long Giao tiễn phá giải.","nguon":["@c0312"]},{"id":"bao-thuat-huyen-vu","name":"Bảo thuật Huyền Vũ","cn":"","loai":"than-thong","loaiLabel":"Bảo thuật","phamCap":"","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Bảo thuật gọi ra Huyền Vũ, vừa có khả năng phòng ngự vừa có thể phá công kích bằng phù văn.","detail":"Thạch Hạo gọi Huyền Vũ xuất hiện từ biển lớn phía sau. Huyền Vũ luyện hóa phù kiếm, xoay tròn thành tấm khiên mang đồ án hình Quy rồi đạp vỡ toàn bộ ba mươi sáu thanh phù kiếm của Thạch Tử Đằng.","nguon":["@c0312"]},{"id":"bao-thuat-kim-o","name":"Bảo thuật Kim Ô","cn":"","loai":"than-thong","loaiLabel":"Bảo thuật","phamCap":"","hePhai":"","soHuu":["Thạch Tử Đằng"],"blurb":"Bảo thuật cô đọng áo nghĩa thần thông thành Kim Ô mang ánh lửa mãnh liệt để công kích.","detail":"Thạch Tử Đằng cô đọng bảo thuật vào một chưởng, phóng ra Kim Ô bao phủ bởi vô tận ánh lửa. Trình độ thi triển của hắn đã đạt mức xuất thần nhập hóa, đủ sức trực diện đối đầu với Toan Nghê và lôi điện của Thạch Hạo.","nguon":["@c0312"]},{"id":"bao-thuat-thien-hac","name":"Bảo thuật Thiên Hạc","cn":"","loai":"than-thong","loaiLabel":"Bảo thuật","phamCap":"","hePhai":"","soHuu":["Thạch Tử Đằng"],"blurb":"Bảo thuật dùng phù văn bao phủ người thi triển, tạo thành sinh linh mang chiếc đuôi đỏ sắc bén để đánh vào yếu huyệt đối thủ.","detail":"Khi Thạch Tử Đằng thi triển, phù văn lưu chuyển quanh thân và hình thành một sinh linh được gọi là Thiên Hạc, có hình dáng giống bò cạp. Mũi đuôi đỏ đâm thẳng vào mi tâm Thạch Hạo nhưng bị cánh Côn Bằng ngăn lại.","nguon":["@c0312"]},{"id":"chu-ti-phi-tien","name":"Chu Ti Phi Tiên","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Thái Cổ Ma Chu","soHuu":["Thạch Tử Đằng"],"blurb":"Sát chiêu tạo ra sợi tơ phù văn cực nhỏ, lặng lẽ xuyên kích mục tiêu với tốc độ và độ sắc bén cao.","detail":"Thạch Tử Đằng phóng sợi tơ phù văn mảnh hơn tóc nhằm thẳng vào đầu Thạch Hạo. Sợi tơ lặng yên, khó phòng bị, có độ cứng và sức xuyên thấu đủ để xuyên thủng nhiều bảo cụ; Thạch Hạo chỉ tránh được nhờ kịp thời cảm ứng nguy hiểm.","nguon":["@c0312"]},{"id":"bao-thuat-ma-chu-nhat-mach","name":"Bảo thuật Ma Chu nhất mạch","cn":"","loai":"than-thong","loaiLabel":"Bảo thuật","phamCap":"","hePhai":"Ma Chu nhất mạch","soHuu":["Thạch Tử Đằng"],"blurb":"Bảo thuật của Ma Chu nhất mạch, được Thạch Tử Đằng dùng để chống lại bảo thuật Toan Nghê của Thạch Hạo.","detail":"Khi thi triển, bảo thuật tạo thành một dải phù văn như ngân hà để phòng ngự trước mười con Toan Nghê cùng biển sét.","nguon":["@c0313"]},{"id":"an-con-bang","name":"Ấn Côn Bằng","cn":"","loai":"than-thong","loaiLabel":"Bảo ấn","phamCap":"","hePhai":"Côn Bằng","soHuu":["Thạch Hạo"],"blurb":"Bảo ấn do Thạch Hạo kết thành từ sức mạnh Côn Bằng.","detail":"Thạch Hạo kết Ấn Côn Bằng và đánh thẳng về phía trước, phá tan hình Chân Long đỏ do Long Huyết Chiến kích phóng ra.","nguon":["@c0313"]},{"id":"sat-tran-thuong-co-trong-hoang-cung","name":"Sát trận Thượng Cổ trong hoàng cung","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Thượng Cổ","hePhai":"Thạch Quốc","soHuu":["Nhân Hoàng"],"blurb":"Sát trận đặt trong hoàng cung Thạch Quốc, là một phần nội tình khiến cường giả cấp Tôn giả phải e dè.","detail":"Một khi được mở ra, sát trận có thể khiến ngay cả Tôn giả ôm hận. Sức răn đe của trận pháp cùng địa lợi Hoàng Đô là nguyên nhân khiến Thái Cổ Ma Chu không muốn tùy tiện giao chiến với Nhân Hoàng.","nguon":["@c0314"]},{"id":"bo-thien-thuat","name":"Bổ Thiên thuật","cn":"","loai":"than-thong","loaiLabel":"Bảo thuật","phamCap":"","hePhai":"Thượng Cổ Thánh Viện","soHuu":["Thạch Nghị"],"blurb":"Bảo thuật Thạch Nghị đạt được tại Thượng Cổ Thánh Viện, được cho là có thể giúp hắn bù đắp khuyết điểm và trở nên hoàn mỹ.","detail":"Dư luận cho rằng Bổ Thiên thuật có khả năng hóa giải vấn đề do Chí Tôn cốt trong cơ thể Thạch Nghị không phải tự sinh, qua đó giúp nền tảng của Trùng Đồng giả trở nên hoàn thiện hơn.","nguon":["@c0314"]},{"id":"muoi-dai-dong-thien","name":"Mười đại Động Thiên","cn":"","loai":"khac","loaiLabel":"Cấu trúc tu luyện","phamCap":"","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Mười Động Thiên cung cấp cho Thạch Hạo lượng thần lực dồi dào và có thể hiển hóa để giam cầm đối thủ.","detail":"Nhờ mười Động Thiên, Thạch Hạo vẫn duy trì được sức chiến đấu sau khi đối phương hao cạn thần lực. Khi ba thiếu niên bỏ chạy, các Động Thiên hiển hóa và giam cầm họ lại.","nguon":["@c0319"]},{"id":"luyen-than-dai-tran","name":"Luyện Thần đại trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"Hoàng cung Thạch tộc","soHuu":["Thạch tộc"],"blurb":"Đại trận hộ vệ hoàng cung, tự thức tỉnh khi cảm nhận nguy cơ và áp chế sức mạnh vượt quá cấp vương hầu.","detail":"Khi vận chuyển, đại trận hiển hóa thành tinh hải với hơn vạn đại tinh mang phù văn và phát ra thần uy. Trận pháp liên tiếp ngăn công kích của Thanh Thiên tôn giả và Thái Cổ Ma Chu, đồng thời bảo vệ hoàng tộc cùng các trọng địa trong hoàng cung.","nguon":["@c0320"]},{"id":"mang-nhen-mau-vang","name":"Mạng nhện màu vàng","cn":"","loai":"than-thong","loaiLabel":"Bảo thuật","phamCap":"","hePhai":"","soHuu":["Kim Chu"],"blurb":"Bảo thuật giăng nhiều tầng tơ nhện vàng phủ kín bầu trời để bao vây và trói giữ đối thủ.","detail":"Tơ nhện có độ dẻo dai cao, khó phá hủy và từng suýt khiến Thạch Hạo chịu thiệt lớn trong trận chiến với Kim Chu.","nguon":["@c0322"]},{"id":"trieu-hoan-anh-linh","name":"Triệu hoán anh linh","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Cấm thuật","hePhai":"","soHuu":[],"blurb":"Cấm thuật được những người chứng kiến suy đoán có khả năng triệu hoán chiến hồn đã chết, ngưng tụ pháp thể để tham chiến.","detail":"Những người chứng kiến cho rằng các bóng mờ hung thú trong lốc xoáy là chiến hồn được triệu hoán bằng một loại cấm thuật. Theo truyền thuyết được nhắc tới, phương thức này có thể cần hiến tế hoặc thiêu đốt sinh mệnh, nhưng chương chưa xác nhận Thạch Hạo thực sự tu luyện hay thi triển nó.","nguon":["@c0324"]},{"id":"truyen-tong-tran-co-dien-hoa-quoc","name":"Truyền tống trận cổ điện Hỏa Quốc","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"Hỏa Quốc","soHuu":["Hỏa Quốc"],"blurb":"Trận pháp truyền tống đặt trong cổ điện giữa sa mạc Hỏa Quốc, dùng phù văn mở thông đạo đưa người từ nơi khác tới.","detail":"Khi được kích hoạt, phù văn trong cổ điện phát sáng và người truyền tống xuất hiện bên trong cung điện.","nguon":["@c0327"]},{"id":"than-thong-loi-dien-hoa-thu","name":"Thần thông lôi điện hóa thủ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chưa rõ","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Thần thông lôi điện có thể phá kiếm khí và biến hóa thành bàn tay lớn để khống chế nhiều mục tiêu.","detail":"Thạch Hạo phóng tia điện màu tím xé nát kiếm khí, sau đó khiến lôi điện hóa thành cuồng phong và ngưng tụ bàn tay màu tím, bắt giữ nhóm quý tộc Hỏa Quốc cùng những con sói đỏ.","nguon":["@c0328"]},{"id":"ban-tay-hoa-song-vang","name":"Bàn tay hóa sóng vàng","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chưa rõ","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Thần thông biến bàn tay thành sóng vàng để kéo mục tiêu từ xa.","detail":"Thạch Hạo đưa tay hóa thành một vùng sóng biển màu vàng, định kéo người đang rơi xuống ao dung nham trở lại nhưng không kịp cứu đối phương.","nguon":["@c0328"]},{"id":"toan-nghe-an","name":"Toan Nghê ấn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Thần thông kết ấn khiến bàn tay hóa thành Toan Nghê để công kích, có thể đánh tan bảo cụ.","detail":"Khi thi triển, bàn tay mang hình thái Thái Cổ hung thú và phát ra âm thanh như giông tố. Thạch Hạo dùng một kích phá nát bảo cụ của nhóm người tranh đoạt hoa sen xanh.","nguon":["@c0329"]},{"id":"phu-van-thu-thach-than-phu","name":"Phù văn thử thách thần phủ","cn":"","loai":"khac","loaiLabel":"Trận cấm cửa điện","phamCap":"","hePhai":"","soHuu":[],"blurb":"Hệ thống phù văn trước cửa thần phủ dùng để sàng lọc người muốn tiến vào cung điện.","detail":"Phù văn có thể phá hủy bảo cụ và tiêu diệt người cưỡng ép vượt cửa. Người tham gia phải chống đỡ bằng nhục thân hoặc vận dụng bảo thuật cùng hiểu biết về phù văn để phá giải, vì chỉ có thể thông qua vùng phù văn này thì mới có thể tiến vào trong.","nguon":["@c0330"]},{"id":"phap-mon-dien-hoa-than-hi-chua-dat-ten","name":"Pháp môn diễn hóa thần hi chưa đặt tên","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Pháp môn tự sáng tạo","phamCap":"Chưa xác định","hePhai":"Thạch Hạo tự sáng tạo","soHuu":["Thạch Hạo"],"blurb":"Phương thức do Thạch Hạo tự mở ra khi tìm đường vượt cực cảnh Hóa Linh, lấy việc biến đổi thần hi và tái cấu trúc cốt văn làm nền tảng.","detail":"Thạch Hạo áp chế từng sợi thần hi thành tháp, chuông, lò lửa hoặc binh khí rồi dùng chúng tổ hợp lại cốt văn. Hình thái binh khí tăng công kích, chuông và tháp tăng phòng ngự, còn lò lửa làm thần lực dâng cao; phương thức này cũng được mở rộng sang sức mạnh tinh thần và quá trình rèn luyện huyết nhục.","thuocTinh":"Biến đổi thần hi và tái cấu trúc cốt văn","nguonGoc":"Do Thạch Hạo tự sáng tạo trong đại điện ngộ đạo thời xưa.","yeuCau":"Điều khiển và áp chế từng sợi thần hi để tạo thành hình thái cụ thể.","uyLuc":"Có thể tăng cường công kích, phòng ngự và thần lực tùy theo hình thái thần hi.","dacDiem":"Cho phép chuyển đổi nhanh hoặc đồng thời duy trì nhiều hình thái thần hi; thử nghiệm thất bại có thể khiến người tu thổ huyết và thân thể bị xé rách.","chieuTieuBieu":["Thần hi hóa tiểu tháp","Thần hi hóa chuông","Thần hi hóa lò lửa","Thần hi hóa binh khí"],"trangThai":"Bước đầu thành công","congNang":["Tái cấu trúc cốt văn bằng những sợi thần hi đã được tạo hình.","Tăng lực công kích khi thần hi hóa thành kiếm, chiến mâu, mũi tên và các hình thái binh khí.","Tăng khả năng phòng ngự khi thần hi hóa thành chuông hoặc tháp.","Làm thần lực dâng cao khi thần hi hóa thành lò lửa.","Hỗ trợ rèn luyện sức mạnh tinh thần và huyết nhục."],"nguoiTu":[{"ten":"Thạch Hạo","tuChuong":"@c0331","tangDatToi":"Bước đầu thành công","trangThai":"Đang hoàn thiện"}],"tabs":{"tienTrinh":[{"chuong":"@c0331","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Bước đầu sáng tạo","text":"Thạch Hạo rèn thần hi thành nhiều hình thái, dùng chúng tái cấu trúc cốt văn và bước đầu xác lập một con đường tu luyện riêng.","anchor":"Nó áp chế mỗi một sợi thần hi hóa thành tiểu tháp"}]},"capNhatToi":"@c0331","nguon":["@c0331"]},{"id":"than-hi-hoa-chuong-va-tieu-kiem","name":"Thần hi hóa chuông và tiểu kiếm","cn":"","loai":"than-thong","loaiLabel":"Đạo vận Hóa Linh","phamCap":"Cực cảnh Hóa Linh","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Con đường biến đổi từng sợi thần hi thành chuông nhỏ để phòng ngự hoặc tiểu kiếm để công kích. Đây là đạo giúp Thạch Hạo phá cực cảnh Hóa Linh.","detail":"Khi thần hi hóa thành vô số chuông nhỏ, toàn thân Thạch Hạo giống một chiếc chuông vàng phát ra gợn sóng và nghiền nát mũi tên hoàng kim. Khi chuyển thành tiểu kiếm, sức mạnh trở nên sắc bén, thích hợp cho đòn chém áp sát.","thuocTinh":"Biến đổi thần hi","nguonGoc":"Đạo do Thạch Hạo lĩnh ngộ khi phá cực cảnh Hóa Linh.","yeuCau":"Điều động thần hi và cốt văn trong máu thịt.","uyLuc":"Hình thái chuông nghiền nát mũi tên thứ ba của thiên tài Minh Văn cảnh, còn hình thái tiểu kiếm chém rách da đầu đối thủ.","dacDiem":"Mỗi sợi thần hi có thể chuyển đổi giữa hình thái chuông và tiểu kiếm.","chieuTieuBieu":["Thần hi hóa chuông","Thần hi hóa tiểu kiếm"],"trangThai":"Đã được Thạch Hạo đưa vào thực chiến","congNang":["Biến thần hi thành chuông nhỏ, hợp thành thế phòng ngự phát ra gợn sóng.","Biến thần hi thành tiểu kiếm để tăng sức công kích khi áp sát."],"nguoiTu":[{"ten":"Thạch Hạo","tuChuong":"@c0332","tangDatToi":"Cực cảnh Hóa Linh","trangThai":"Đang tu luyện"}],"capNhatToi":"@c0332","tabs":{"tienTrinh":[{"chuong":"@c0332","loai":"thi triển","importance":"major","giaiDoan":"Hiển lộ trong thực chiến","text":"Thạch Hạo dùng hình thái chuông nghiền nát mũi tên hoàng kim, sau đó chuyển thần hi thành tiểu kiếm để phản kích.","anchor":"Đây là Đạo mà nó vừa mới tìm hiểu được, dựa vào thứ này để đột phá cực cảnh Hóa Linh"}]},"nguon":["@c0332"]},{"id":"than-thong-huyen-vu","name":"Thần thông Huyền Vũ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Thần thông phòng ngự được Thạch Hạo kết hợp với đỉnh văn để diễn hóa Huyền Quy, biển đen và khiên mai rùa.","detail":"Thạch Hạo dùng các đỉnh nhỏ tổ hợp thành phù văn, tạo ra Huyền Quy cùng biển đen để chống mũi tên vàng. Huyền Quy sau đó hóa thành một tấm khiên mai rùa dày đặc phù văn, nhưng lớp phòng ngự này vẫn bị đòn công kích của cường giả Minh Văn cảnh xuyên thủng.","nguon":["@c0333"]},{"id":"canh-con-bang","name":"Cánh Côn Bằng","cn":"","loai":"than-thong","loaiLabel":"Thần thông thân pháp","phamCap":"","hePhai":"Côn Bằng","soHuu":["Thạch Hạo"],"blurb":"Đôi cánh vàng có vằn đen giúp Thạch Hạo tăng mạnh tốc độ và né tránh công kích.","detail":"Thạch Hạo hiển hóa cánh Côn Bằng để nhanh chóng vượt khỏi vùng hủy diệt của tám viên lôi châu, sau đó vòng tới phía sau thiếu niên tóc vàng và áp sát đối thủ.","nguon":["@c0333"]},{"id":"thuat-loi-dao","name":"Thuật Lôi đạo","cn":"","loai":"khac","loaiLabel":"Pháp thuật","phamCap":"","hePhai":"Lôi đạo","soHuu":["Thiếu niên tóc vàng"],"blurb":"Pháp thuật Lôi đạo ngưng tụ tám viên lôi châu có sức phá hoại mạnh mẽ.","detail":"Thiếu niên tóc vàng đồng thời ngưng tụ tám viên lôi châu, mỗi viên được mô tả có thể hủy diệt một ngọn núi cao. Khi chúng phát nổ, khu vực chiến đấu rung chuyển dữ dội và hồ dung nham bị sấy khô.","nguon":["@c0333"]},{"id":"bao-thuat-phong-loi-vu-toc","name":"Bảo thuật Phong Lôi Vũ tộc","cn":"","loai":"than-thong","loaiLabel":"Bảo thuật chủng tộc","phamCap":"","hePhai":"Phong Lôi Vũ tộc","soHuu":["Thiếu niên tóc vàng"],"blurb":"Bảo thuật thiên phú của Phong Lôi Vũ tộc, vận dụng cánh Phong Lôi để điều khiển phong lôi và gia tăng tốc độ.","detail":"Thiếu niên tóc vàng khiến cánh Phong Lôi sau lưng hóa thành màu vàng óng, đan xen tia chớp để công kích và di chuyển. Năng lực này được giới thiệu là thiên phú chủng tộc của Phong Lôi Vũ tộc.","nguon":["@c0333"]},{"id":"dai-tran-phu-van","name":"Đại trận phù văn","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"Tộc Viêm Mãng","soHuu":["Tộc Viêm Mãng"],"blurb":"Trận pháp được bí mật dựng quanh chiến trường tranh đoạt kinh văn, dùng để phong tỏa và nghiền ép những người mắc kẹt bên trong.","detail":"Những kẻ ẩn nấp kích hoạt trận pháp khi hơn nghìn người đang hỗn chiến. Uy thế của đại trận bao phủ khu vực, biến nơi tranh đoạt kinh văn thành một sát cục nhằm khống chế những người có mặt.","nguon":["@c0335"]},{"id":"huyet-te-dai-tran","name":"Huyết tế đại trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"Tộc Viêm Mãng","soHuu":["Tộc Viêm Mãng"],"blurb":"Sát trận lấy sinh mạng người sống làm tế phẩm, dẫn huyết quang về hồ dung nham để mở Thượng Cổ Thánh Hoàng cung.","detail":"Đại trận nghiền hàng chục người thành thịt nát và hút huyết quang về hồ dung nham. Tộc Viêm Mãng định hiến tế hơn nghìn người để mở cung điện, nhưng toàn bộ phù văn sau đó bị cờ lớn màu vàng phá tan.","nguon":["@c0335"]},{"id":"dao-hoa-cua-thach-hao","name":"Đạo hỏa của Thạch Hạo","cn":"","loai":"than-thong","loaiLabel":"Thần thông luyện hóa","phamCap":"Chưa rõ","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Đạo hỏa được Thạch Hạo điều khiển để luyện chủ dược, chiết xuất vật chất thần tính theo phương thuốc cổ.","detail":"Thạch Hạo cẩn thận khống chế đạo hỏa của bản thân để luyện hóa huyết nhục hung thú trong chén Hóa Thiên. Quá trình này tiêu hao nhiều tâm thần, biến phần lớn thân xác thành tro và giữ lại tinh hoa thần tính dạng chất lỏng.","nguon":["@c0336"]},{"id":"luc-con-bang","name":"Lực Côn Bằng","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Côn Bằng","soHuu":["Thạch Hạo"],"blurb":"Lực lượng Côn Bằng được Thạch Hạo triển khai để phá hủy dị bảo.","detail":"Thạch Hạo vận dụng lực Côn Bằng, phối hợp với mười đại Động Thiên giam cầm khu vực, dùng tay không bóp tấm biển đồng thau của Hồ Ma Linh thành bột mịn.","nguon":["@c0340"]},{"id":"van-chu-vong","name":"Vạn Chu Võng","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Hồ Ma Linh","soHuu":["Hồ Ma Linh"],"blurb":"Thần thông tạo thành mạng nhện để vây khốn và tiêu diệt đối thủ.","detail":"Phía Hồ Ma Linh phát động Vạn Chu Võng nhằm vây giết Thạch Hạo, nhưng toàn bộ mạng nhện bị thần hi hóa thành lò thần thiêu cháy.","nguon":["@c0341"]},{"id":"dai-tran-than-linh-ho-ma-linh","name":"Đại trận Thần Linh Hồ Ma Linh","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Thần Linh","hePhai":"Hồ Ma Linh","soHuu":["Hồ Ma Linh"],"blurb":"Trận pháp do Thần Linh lưu lại tại Hồ Ma Linh, có khả năng phong tỏa và trấn áp cổ địa.","detail":"Đại trận được điều khiển bằng trận kỳ, khiến khí tức cổ địa biến đổi để trấn áp Thạch Hạo. Tầng thứ nhất bị hộ tí của Thần phá nát, nhưng Hồ Ma Linh sau đó tiếp tục kích hoạt tầng thứ hai.","nguon":["@c0341"]},{"id":"chuong-vang-ho-than","name":"Chuông vàng hộ thần","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Thần thông ứng biến giúp Thạch Hạo chống lại sức áp chế của Trùng Đồng và bảo vệ thần thức.","detail":"Đôi mắt, thần thức và thân thể Thạch Hạo lần lượt hiện thành hình thái chuông vàng. Tiếng chuông chống sự trầm luân, gột rửa hồn phách và đánh thức những người quan chiến đang chịu ảnh hưởng từ Trùng Đồng.","nguon":["@c0342"]},{"id":"cam-che-ho-ma-linh","name":"Cấm chế hồ Ma Linh","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"","soHuu":[],"blurb":"Hệ thống đại trận và cấm chế được bố trí quanh chiến trường tại hồ Ma Linh.","detail":"Các cấm chế và đại trận quanh hồ Ma Linh bị quyền phong, phù văn cùng dư lực từ cuộc giao chiến giữa Thạch Hạo và Thạch Nghị phá vỡ.","nguon":["@c0342"]},{"id":"kim-cuong-bat-hoai-than","name":"Kim Cương Bất Hoại Thân","cn":"","loai":"luyen-the","loaiLabel":"Pháp thân luyện thể","phamCap":"Pháp thân cực hạn","hePhai":"Tây Thiên giáo","soHuu":["Tây Thiên giáo"],"blurb":"Pháp thân cực hạn của Tây Thiên giáo, đạt tới cảnh giới vạn kiếp bất hủ và có thể chống đỡ bảo cụ chư thiên.","detail":"Kim Cương Bất Hoại Thân chú trọng rèn luyện thân thể tới mức sau khi chết vẫn không hủy, được xem là pháp thân cực hạn của Tây Thiên giáo.","nguon":["@c0343"]},{"id":"suc-manh-trung-dong","name":"Sức mạnh Trùng Đồng","cn":"","loai":"than-thong","loaiLabel":"Thần năng thiên phú","phamCap":"Sức mạnh cấm kỵ","hePhai":"","soHuu":["Thạch Nghị"],"blurb":"Thần năng phát xuất từ Trùng Đồng của Thạch Nghị, có thể phóng ra thần lực và phù văn đáng sợ bao phủ toàn thân.","detail":"Khi được kích hoạt, thần lực tuôn ra từ hốc mắt và phù văn trong con ngươi hiện lên như một bộ kinh cổ mở ra, kèm theo tiếng tụng kinh phảng phất vọng tới từ thời Thượng Cổ.","nguon":["@c0343"]},{"id":"than-hi-hoa-hinh","name":"Thần hi hóa hình","cn":"","loai":"cong-phap","loaiLabel":"Phương pháp tu hành","phamCap":"","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Phương pháp biến thần hi thành các hình thể và ký hiệu nguyên thủy, gắn liền với con đường tiến tới thành Thần.","detail":"Thạch Hạo đã dùng thần hi hóa thành đỉnh, chuông và Côn Bằng từ Hóa Linh cảnh, nhờ đó đột phá cực cảnh. Hỏa Hoàng chỉ ra rằng việc tiếp tục hóa thành Toan Nghê, Huyền Vũ, Côn Bằng và ngưng tụ vô số ký hiệu nguyên thủy là vấn đề có thể kéo dài tới khi thành Thần.","nguon":["@c0346"]},{"id":"cam-che-than-hon-bao-ho-truyen-thua","name":"Cấm chế thần hồn bảo hộ truyền thừa","cn":"","loai":"bi-thuat","loaiLabel":"Cấm chế","phamCap":"","hePhai":"Các giáo phái vực ngoại","soHuu":["Thiếu niên một sừng","Người trẻ tuổi tộc bốn mắt","Thiếu nữ Phiêu Miểu cung"],"blurb":"Cấm chế dùng phù văn có tính hủy diệt khắc vào thần hồn đệ tử nhằm bảo vệ truyền thừa quan trọng của giáo phái.","detail":"Khi ba tù binh vực ngoại định tiết lộ bảo thuật trấn giáo, cấm chế khiến mi tâm họ rạn nứt và chảy máu. Nếu tiếp tục cưỡng ép truyền đạt, phù văn có thể hủy diệt thần hồn của người mang cấm chế.","nguon":["@c0349"]},{"id":"dai-than-thong-toc-chu-tuoc","name":"Đại thần thông tộc Chu Tước","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Đại thần thông","hePhai":"Tộc Chu Tước","soHuu":["Tiểu Hồng điểu"],"blurb":"Bảo thuật cao thâm của tộc Chu Tước, được Tiểu Hồng điểu xem là tương xứng với bảo thuật Chân Long.","detail":"Tiểu Hồng điểu từ chối truyền môn thần thông này cho Thạch Hạo vì cho rằng công pháp quá rườm rà, cao thâm và người học cần thiên tư, ngộ tính thích hợp. Nó chỉ chấp nhận cân nhắc trao đổi nếu Thạch Hạo đưa ra bảo thuật Chân Long.","nguon":["@c0351"]},{"id":"phap-tac-khong-gian-thanh-hoang-cung","name":"Pháp tắc không gian Thánh Hoàng cung","cn":"","loai":"khac","loaiLabel":"Trận pháp không gian","phamCap":"Chưa rõ","hePhai":"Thánh Hoàng cung","soHuu":[],"blurb":"Pháp tắc không gian bảo vệ Thánh Hoàng cung, khiến người tiếp cận luôn bị giữ ở một khoảng cách bất biến.","detail":"Pháp tắc bao phủ biển dung nham quanh Thánh Hoàng cung. Người tiến vào dù bay rất lâu vẫn không thể tới cung điện nếu không được cầu hoàng kim dẫn đường hoặc tự kết nối với các phù văn trong hư không để dựng cầu thần.","nguon":["@c0352"]},{"id":"cau-than-bay-mau","name":"Cầu thần bảy màu","cn":"","loai":"khac","loaiLabel":"Thủ đoạn phù văn","phamCap":"Chưa rõ","hePhai":"Hóa Linh","soHuu":["Thạch Hạo","Thánh Hoàng"],"blurb":"Cây cầu phù văn bảy màu có thể vượt qua pháp tắc không gian quanh Thánh Hoàng cung.","detail":"Thạch Hạo biến hóa thần hi thành chuông, đỉnh và nhiều hình thái khác, khiến chúng cộng hưởng với những phù văn như sao trong hư không để dựng thành cầu. Khi còn niên thiếu, Thánh Hoàng cũng từng xây dựng được cầu thần bảy màu.","nguon":["@c0352"]},{"id":"chan-hoa-cua-thanh","name":"Chân hỏa cửa thánh","cn":"","loai":"khac","loaiLabel":"Cấm chế khảo nghiệm huyết mạch","phamCap":"Chưa rõ","hePhai":"Thánh Hoàng cung","soHuu":[],"blurb":"Chân hỏa tại cửa Thánh Hoàng cung dùng để sàng lọc huyết thống của người tiến vào.","detail":"Ngọn lửa bùng lên khi có người bước qua cửa thánh và có thể thiêu kẻ không đủ huyết thống thành tro. Hỏa Linh Nhi được chân hỏa bao phủ nhưng thân thể không tổn hại, đồng thời mi tâm xuất hiện dấu ấn đỏ giống Chu Tước nhỏ.","nguon":["@c0352"]},{"id":"duc-hoa-luyen-kim-than","name":"Dục hỏa luyện kim thân","cn":"","loai":"luyen-the","loaiLabel":"Luyện thể","phamCap":"","hePhai":"Hỏa đạo","soHuu":["Thạch Hạo"],"blurb":"Phương thức dùng chân hỏa rèn luyện thể xác từ da thịt đến phủ tạng và cốt tủy. Thạch Hạo trải qua quá trình này để hoàn thành thân thể Minh Văn cảnh.","detail":"Người không có huyết mạch Hỏa đạo phải dựa vào tinh thần và thể xác để chống chịu chân hỏa. Ngọn lửa thiêu lớp da cũ, thấm sâu vào phủ tạng và cốt tủy, sau đó vật chất thần tính trong lửa bồi bổ, giúp thân thể hồi phục và hoàn tất quá trình tế luyện ở Minh Văn cảnh.","nguon":["@c0353"]},{"id":"bon-kich-cua-thai-co-chu-tuoc","name":"Bốn kích của Thái Cổ Chu Tước","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Bốn kích chưa hoàn chỉnh","hePhai":"Hỏa tộc","soHuu":[],"blurb":"Pháp môn công kích được nhiều đời thần nhân nghiên cứu nhằm phục hồi bảo thuật Thái Cổ Chu Tước.","detail":"Pháp môn gồm bốn kích có thể thi triển nhưng đòi hỏi thể phách sánh ngang Thái Cổ Chu Tước. Người có thân thể không đủ mạnh sẽ tự rạn nứt và có thể chết trước khi hạ được đối thủ; nếu tiếp tục thôi diễn đủ mười kích thì có khả năng tái hiện bảo thuật Chu Tước vô thượng.","nguon":["@c0354"]},{"id":"thanh-hoang-kinh","name":"Thánh Hoàng kinh","cn":"","loai":"cong-phap","loaiLabel":"Kinh cổ truyền thừa","phamCap":"Kinh cổ của Thượng Cổ Thánh Hoàng","hePhai":"Hỏa tộc","soHuu":["Hỏa Linh Nhi"],"blurb":"Kinh cổ do Thượng Cổ Thánh Hoàng để lại, gắn với huyết mạch và truyền thừa của Hỏa tộc.","detail":"Người có duyên phải ngồi nghe và tự lĩnh ngộ, còn nội dung tiếp nhận có thể khác nhau tùy từng người. Hỏa Linh Nhi cộng hưởng với kinh cổ nhờ truyền thừa Hỏa tộc; người ngoài Hỏa tộc muốn cầu tạo hóa phải trải qua thử thách riêng.","nguon":["@c0354"]},{"id":"phu-van-co-ban-cua-hoa-toc","name":"Phù văn cơ bản của Hỏa tộc","cn":"","loai":"cong-phap","loaiLabel":"Khẩu quyết cơ bản","phamCap":"Cơ bản","hePhai":"Hỏa tộc","soHuu":["Hỏa Linh Nhi","Thạch Hạo"],"blurb":"Đoạn khẩu quyết cơ bản của Hỏa tộc đã được lưu truyền bên ngoài và có thể tạo cộng hưởng với Thánh Hoàng kinh.","detail":"Hỏa Linh Nhi truyền pháp môn này cho Thạch Hạo. Sau khi hiểu và vận chuyển phù văn, Thạch Hạo có thể cộng hưởng với kinh cổ và nhìn thấy những hướng truyền thừa để lựa chọn.","nguon":["@c0354"]},{"id":"bao-thuat-thai-co-chu-tuoc","name":"Bảo thuật Thái Cổ Chu Tước","cn":"","loai":"than-thong","loaiLabel":"Bảo thuật vô thượng","phamCap":"Truyền thừa hoàn chỉnh","hePhai":"Thái Cổ Chu Tước","soHuu":[],"blurb":"Bảo thuật vô thượng của Thái Cổ Chu Tước, có uy lực thiêu hủy chư thiên thần ma.","detail":"Truyền thừa hoàn chỉnh của bảo thuật này không có tại Hoang Vực. Nhiều đời cường giả mang chân huyết Chu Tước đã nghiên cứu cách phục hồi nhưng chỉ để lại Bốn kích của Thái Cổ Chu Tước chưa hoàn chỉnh.","nguon":["@c0354"]},{"id":"bao-thuat-chi-ton","name":"Bảo thuật Chí Tôn","cn":"","loai":"than-thong","loaiLabel":"Bảo thuật bẩm sinh","phamCap":"","hePhai":"Nhân tộc","soHuu":["Thạch Hạo"],"blurb":"Bảo thuật độc nhất do Chí Tôn cốt bẩm sinh thai nghén, được Thạch Hạo nhận định là con đường phù hợp nhất với mình.","detail":"Phù văn trên Chí Tôn cốt ngưng tụ thành một người tí hon sáng rực ngồi tụng kinh, thể hiện áo nghĩa riêng của Nhân tộc thay vì hóa thành hung cầm hay mãnh thú như bảo thuật thông thường. Bảo thuật vẫn chưa hoàn chỉnh vì khối cốt tái sinh chưa trưởng thành; việc cưỡng ép vận dụng có thể phát ra uy lực xuyên thủng cung điện nhưng cũng phản chấn Thạch Hạo đến mức trọng thương và thần hồn lìa khỏi thân thể.","nguon":["@c0357"]},{"id":"cat-ngang-bien-xanh","name":"Cắt ngang biển xanh","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Thạch Hạo"],"blurb":"Đòn đánh tạo thanh thế lớn, cắt đứt đường tiến của đàn hung thú và quấy nhiễu chiến trận.","detail":"Thạch Hạo thi triển đòn đánh này khi đối phó hơn trăm phù thú Minh Văn cảnh trong sân thi đấu của Bức tường Thần Ma. Uy lực của nó chặn đường tiến và làm rối loạn thế liên kết của đàn hung thú, tạo cơ hội để Thạch Hạo xông vào cận chiến.","nguon":["@c0358"]},{"id":"thuat-luyen-the-cua-chu-yem","name":"Thuật luyện thể của Chu Yếm","cn":"","loai":"luyen-the","loaiLabel":"Luyện thể","phamCap":"Không rõ","hePhai":"Chu Yếm","soHuu":["Chu Yếm Thái Cổ"],"blurb":"Pháp môn luyện thể nổi danh của Chu Yếm, giúp giống loài này sở hữu thể phách cực kỳ mạnh mẽ.","detail":"Thuật luyện thể này được đánh giá là vang dội cổ kim. Chu Yếm thời Thái Cổ nhờ thể phách cường đại có thể xé rách Thần Ma và lấy các cường giả làm thức ăn; Chu Yếm trấn giữ sân thi đấu cũng chịu một quyền của Thạch Hạo mà không bị thương.","nguon":["@c0358"]},{"id":"canh-chu-tuoc","name":"Cánh Chu Tước","cn":"","loai":"than-thong","loaiLabel":"Thần thông huyết thống","phamCap":"Không rõ","hePhai":"Huyết thống Chu Tước","soHuu":["Hỏa Linh Nhi"],"blurb":"Đôi cánh ánh sáng đỏ tươi xuất hiện sau lưng Hỏa Linh Nhi khi huyết thống Chu Tước thức tỉnh toàn diện.","detail":"Cánh Chu Tước là biểu hiện của huyết thống Chu Tước đã thức tỉnh toàn diện trong cơ thể Hỏa Linh Nhi. Khi đôi cánh ánh sáng đỏ tươi vỗ lên, xích hà rực rỡ lan tỏa.","nguon":["@c0360"]},{"id":"tran-phap-hang-chu-tuoc","name":"Trận pháp hang Chu Tước","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Thánh Hoàng Thượng Cổ","soHuu":[],"blurb":"Trận pháp do Thánh Hoàng Thượng Cổ bố trí để bảo vệ hang Chu Tước, có thể đánh bật người không được hang cổ tiếp nhận.","detail":"Trận pháp bao phủ khu vực hang Chu Tước và dùng phù văn đánh bật Thạch Hạo khi cậu tìm cách tiếp cận. Hỏa Linh Nhi nhờ có sự đồng cảm với hang cổ nên có thể vượt qua ngọn lửa và tiến vào bên trong tu hành.","nguon":["@c0360"]},{"id":"chan-hoa-chu-tuoc","name":"Chân hỏa Chu Tước","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Hỏa hệ Chu Tước","soHuu":["Tiểu Hồng"],"blurb":"Chân hỏa của Chu Tước có thể thiêu đốt, bao phủ mục tiêu và dò xét huyết mạch.","detail":"Tiểu Hồng dùng chân hỏa đánh văng Thạch Hạo, sau đó bao phủ Hỏa Linh Nhi để kiểm tra huyết mạch. Ngọn lửa không làm Hỏa Linh Nhi tổn thương; phần hỏa diễm bám quanh Thạch Hạo bị một cọng lông đỏ hấp thu.","nguon":["@c0361"]},{"id":"dan-long-thu","name":"Dẫn Long Thủ","cn":"","loai":"than-thong","loaiLabel":"Bảo thuật","phamCap":"Không trọn vẹn","hePhai":"Bổ Thiên giáo","soHuu":["Thiếu niên Bổ Thiên giáo"],"blurb":"Bảo thuật hóa bàn tay phủ vảy bạc thành hình thái chân long để công kích đối thủ.","detail":"Dẫn Long Thủ có quan hệ với chân long nhưng truyền thừa được thi triển ở đây không trọn vẹn. Khi vận dụng, bàn tay hóa thành chân long hung mãnh; thiếu niên Bổ Thiên giáo từng dùng thuật này tấn công Thạch Hạo nhưng bị phù văn nguyên thủy chặn lại.","nguon":["@c0362"]},{"id":"bon-kich-chu-tuoc-thai-co","name":"Bốn kích Chu Tước Thái Cổ","cn":"","loai":"than-thong","loaiLabel":"Bảo thuật","phamCap":"Thái Cổ","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Bảo thuật Chu Tước gồm bốn kích, được Thạch Hạo vận dụng để áp chế đệ tử nòng cốt của Bổ Thiên giáo.","detail":"Thạch Hạo trước tiên hiện ra hình thức ban đầu của bảo thuật trên lòng bàn tay, sau đó thi triển đòn thứ nhất với dấu ấn Chu Tước đỏ tươi. Đòn đánh khiến thiếu niên Bổ Thiên giáo sắc mặt tái nhợt, khóe miệng trào máu và liên tục lùi lại.","nguon":["@c0362"]},{"id":"suong-mu-an-mon","name":"Sương mù ăn mòn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Thiếu niên phun sương mù ăn mòn"],"blurb":"Thần thông tạo ra sương mù có tính ăn mòn cực mạnh, đủ sức hòa tan đá và bảo cụ.","detail":"Thiếu niên vực ngoại phun sương mù từ miệng để công kích Thạch Hạo. Sương mù phá hủy phần tay áo của y phục hộ thân nhưng không làm tổn thương thân thể Thạch Hạo.","nguon":["@c0365"]},{"id":"huyen-quy-ngung-chuong","name":"Huyền Quy ngưng chưởng","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Thần thông ngưng tụ hình Huyền Quy cùng bàn tay, dùng để ngăn cản và tiêu hao công kích bằng thần lực.","detail":"Thạch Hạo thi triển thần thông này khi đối đầu mũi tên ánh xanh của Hôi Giao. Hình Huyền Quy ngưng tụ cùng bàn tay đã va chạm với mũi tên và làm tiêu hao toàn bộ thần lực chứa trong đó.","nguon":["@c0365"]},{"id":"than-phap-con-bang","name":"Thân pháp Côn Bằng","cn":"","loai":"than-thong","loaiLabel":"Thân pháp","phamCap":"","hePhai":"Côn Bằng","soHuu":["Thạch Hạo"],"blurb":"Thân pháp có tốc độ đứng đầu thiên hạ, được Thạch Hạo vận chuyển để băng qua Đại Hoang.","detail":"Khi phối hợp với Súc Địa phù, thân pháp giúp Thạch Hạo xuyên qua các dãy núi như chớp, để lại một chuỗi tàn ảnh. Tốc độ cực cao khiến bảo y của nó ma sát với không khí rồi hóa thành tro.","nguon":["@c0366"]},{"id":"phap-mon-chua-truyen-cua-lieu-than","name":"Pháp môn chưa truyền của Liễu Thần","cn":"","loai":"khac","loaiLabel":"Pháp môn","phamCap":"Chưa rõ","hePhai":"Liễu Thần","soHuu":[],"blurb":"Một pháp môn Liễu Thần vốn định truyền cho Thạch Hạo, nhưng việc truyền thụ được hoãn lại vì trận quyết chiến đã cận kề và cảnh giới của nó còn chưa thích hợp.","detail":"Liễu Thần dự định chờ đến sau trận quyết chiến hoặc khi cảnh giới của Thạch Hạo phù hợp hơn mới truyền pháp môn này.","nguon":["@c0367"]},{"id":"dai-tran-ly-hoa","name":"Đại trận Ly Hỏa","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"","soHuu":[],"blurb":"Trận pháp do hơn mười dị chủng hợp lực bố trí, có khả năng tru sát sinh linh thuần huyết.","detail":"Hơn mười dị chủng liên thủ vận hành Đại trận Ly Hỏa để đối phó Thạch Nghị, nhưng cả trận pháp lẫn những kẻ bày trận đều bị hắn đánh nổ chỉ bằng một đòn.","nguon":["@c0369"]},{"id":"luoi-xich-than-trat-tu-bao-ve-thien-cung","name":"Lưới xích thần trật tự bảo vệ Thiên cung","cn":"","loai":"khac","loaiLabel":"Trận pháp phòng hộ","phamCap":"","hePhai":"Hồ Ma Linh","soHuu":["Hồ Ma Linh"],"blurb":"Lớp phòng hộ bao phủ Thiên cung trung ương của hồ Ma Linh, được tạo thành từ những xích thần trật tự gần như trong suốt.","detail":"Tấm lưới nhỏ như sợi tóc, bao phủ cung điện khổng lồ và rất khó nhận biết; chỉ tu sĩ đủ mạnh mới có thể phát hiện sự hiện diện của nó.","nguon":["@c0370"]},{"id":"bao-thuat-tu-khi-chua-ro-ten","name":"Bảo thuật tử khí chưa rõ tên","cn":"","loai":"than-thong","loaiLabel":"Bảo thuật","phamCap":"Chưa rõ","hePhai":"Chưa rõ","soHuu":["Thạch Nghị"],"blurb":"Bảo thuật phát ra ánh tím và tử khí từ lòng bàn tay, mang theo khí tức đáng sợ.","detail":"Khi thi triển, lòng bàn tay Thạch Nghị phát ánh tím, khói mờ dâng lên và hóa thành tử khí. Uy thế tỏa ra khiến những người đứng ngoài chiến trường cũng run rẩy.","nguon":["@c0371"]},{"id":"bao-thuat-hoa-diem-chua-ro-ten","name":"Bảo thuật hỏa diễm chưa rõ tên","cn":"","loai":"than-thong","loaiLabel":"Bảo thuật","phamCap":"Chưa rõ","hePhai":"Hỏa","soHuu":["Thạch Hạo"],"blurb":"Bảo thuật vận chuyển thần lực hỏa diễm qua lòng bàn tay, hiện ra ký hiệu cổ điển màu đỏ đậm.","detail":"Thạch Hạo dựng lên một luồng ánh đỏ quanh thân như đang tắm trong lửa, sau đó đưa bàn tay phải về phía trước. Trong lòng bàn tay hiện lên ký hiệu cổ điển đỏ đậm, lấp lánh ánh lửa để nghênh kích Thạch Nghị.","nguon":["@c0371"]},{"id":"phap-mon-ky-lan","name":"Pháp môn Kỳ Lân","cn":"","aliases":["Kỳ Lân bộ"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Hung thuật Thái cổ","hePhai":"Kỳ Lân","soHuu":["Thạch Nghị"],"blurb":"Pháp môn chân chính của Kỳ Lân thuần huyết, giúp người thi triển gia tăng uy thế theo từng bước để đè ép và phá diệt đối thủ.","detail":"Thạch Nghị thi triển Kỳ Lân bộ, mỗi bước đều khiến sức ép và chấn động trong hư không tăng mạnh. Đến bước thứ bảy, pháp môn ép Thạch Hạo lùi lại và chảy máu nơi khóe miệng; một vị Tôn giả nhận định phần truyền thừa Thạch Nghị nắm giữ chưa đầy đủ và hoàn mỹ.","nguon":["@c0372"]},{"id":"phap-tuong-thien-dia","name":"Pháp tướng thiên địa","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Đại thần thông","phamCap":"Đại thần thông","hePhai":"","soHuu":["Thạch Nghị","Thạch Hạo"],"blurb":"Đại thần thông cho phép người thi triển hiện ra và hợp nhất với pháp tướng sinh linh để giao chiến.","detail":"Thạch Nghị hiện pháp tướng Kỳ Lân tím, còn Thạch Hạo hiện pháp tướng Chu Tước đỏ rồi hợp nhất với pháp tướng của mình. Cuộc va chạm giữa hai bên làm chiến trường Thiên Không xuất hiện vết nứt và phá vỡ hơn mười lớp rào chắn bảo hộ.","nguon":["@c0372"]},{"id":"banh-xe-ky-lan","name":"Bánh xe Kỳ Lân","cn":"","loai":"than-thong","loaiLabel":"Tuyệt sát","phamCap":"","hePhai":"Kỳ Lân thuật","soHuu":["Thạch Nghị"],"blurb":"Tuyệt sát do Thạch Nghị ngưng tụ bằng hai tay, có thể trực tiếp va đập hoặc ném khỏi tay để công kích từ xa.","detail":"Bánh xe Kỳ Lân suýt đánh trúng Thạch Hạo, phá nổ hàng chục rào chắn và khiến chiến trường Thiên Không hư hại nghiêm trọng.","nguon":["@c0373"]},{"id":"ky-lan-bo","name":"Kỳ Lân bộ","cn":"","loai":"than-thong","loaiLabel":"Bộ pháp","phamCap":"","hePhai":"Kỳ Lân thuật","soHuu":["Thạch Nghị"],"blurb":"Bộ pháp Kỳ Lân giúp Thạch Nghị áp sát đối thủ, mỗi bước đều cộng hưởng với thiên địa.","detail":"Thạch Nghị liên tiếp đạp ra tám bước, nhanh chóng áp sát Thạch Hạo và khiến khí huyết đối phương sôi trào đến mức chảy máu khóe miệng.","nguon":["@c0373"]},{"id":"bao-thuat-be-ngan","name":"Bảo thuật Bệ Ngạn","cn":"","loai":"than-thong","loaiLabel":"Bảo thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Thạch Nghị"],"blurb":"Bảo thuật biến hóa Bệ Ngạn, giúp Thạch Nghị áp sát và giao chiến trực diện với đối thủ.","detail":"Thạch Nghị vận dụng bảo thuật để hóa thành Bệ Ngạn cuồng bạo, phát huy sức mạnh thô bạo trong cận chiến với Thạch Hạo.","nguon":["@c0374"]},{"id":"bao-thuat-kim-si-dai-bang","name":"Bảo thuật Kim Sí Đại Bàng","cn":"","loai":"than-thong","loaiLabel":"Bảo thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Thạch Nghị"],"blurb":"Bảo thuật giúp Thạch Nghị tăng tốc tới cực hạn và biến bàn tay thành đòn chém màu vàng.","detail":"Trong thế tuyệt sát, Thạch Nghị kết hợp khả năng quan sát của Trùng Đồng với bảo thuật Kim Sí Đại Bàng, tăng tốc tới cực hạn rồi khiến bàn tay hóa vàng và chém xuống nhằm lấy đầu Thạch Hạo.","nguon":["@c0374"]},{"id":"than-phap-dai-bang-canh-vang-hoan-my","name":"Thân pháp Đại Bàng cánh vàng hoàn mỹ","cn":"","loai":"than-thong","loaiLabel":"Thân pháp","phamCap":"Không rõ","hePhai":"Đại Bàng cánh vàng","soHuu":[],"blurb":"Thân pháp có tốc độ súc địa thành thốn, từng được Thạch Nghị xem là một khả năng để lý giải cực tốc của Thạch Hạo.","detail":"Thạch Nghị nhắc tới thân pháp Đại Bàng cánh vàng hoàn mỹ khi suy đoán nguồn gốc tốc độ của Thạch Hạo, trước khi nhận ra đầu mối của thân pháp Côn Bằng.","nguon":["@c0375"]},{"id":"thien-dia-hon-don","name":"Thiên địa hỗn độn","cn":"","loai":"than-thong","loaiLabel":"Thần thông Trùng Đồng","phamCap":"Không rõ","hePhai":"Trùng Đồng","soHuu":["Thạch Nghị"],"blurb":"Thần thông tạo ra sương mù trắng phủ kín chiến trường, giam cầm thân thể và trung hòa ưu thế tốc độ của đối thủ.","detail":"Thạch Nghị triển khai sương mù hỗn độn khắp chiến trường Thiên Không, khiến Thạch Hạo cảm thấy thân thể bị giam cầm và không còn di chuyển tự nhiên bằng cực tốc Côn Bằng.","nguon":["@c0375"]},{"id":"bao-thuat-chu-tuoc","name":"Bảo thuật Chu Tước","cn":"","loai":"than-thong","loaiLabel":"Bảo thuật","phamCap":"Không rõ","hePhai":"Chu Tước","soHuu":["Thạch Hạo"],"blurb":"Bảo thuật được Thạch Hạo vận chuyển cùng phù văn Toan Nghê để tăng sức chiến đấu khi đối đầu chuông vàng.","detail":"Phù văn Chu Tước hiện ra quanh Thạch Hạo trong lúc nó xuyên qua sóng âm, áp sát và liên tiếp dùng quyền công kích đạo binh của Thạch Nghị.","nguon":["@c0375"]},{"id":"luyen-than-nhap-dao-binh","name":"Luyện thần nhập đạo binh","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Chưa rõ","hePhai":"","soHuu":[],"blurb":"Bí pháp dùng kinh văn và phù văn để trói buộc, luyện thần của mục tiêu thành binh hồn.","detail":"Chuông lớn màu vàng vận dụng phương pháp này nhằm phong ấn Thạch Hạo, bao phủ thân thể bằng áo thần phù văn và luyện thần của nó nhập vào đạo binh để làm binh hồn.","nguon":["@c0376"]},{"id":"than-hoa-kiem","name":"Thân hóa kiếm","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chưa rõ","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Thần thông diễn hóa thân thể thành kiếm sắc để công phạt.","detail":"Thạch Hạo hóa chính thân mình thành một thanh kiếm, chém đứt áo thần do phù văn tạo thành rồi liên tục bổ lên chuông lớn màu vàng.","nguon":["@c0376"]},{"id":"dao-binh-hoa-thanh-than-thuat","name":"Đạo binh hóa thành thần thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Chưa rõ","hePhai":"","soHuu":["Thạch Nghị"],"blurb":"Thủ đoạn lấy đạo binh làm vật dẫn để che giấu thần thuật và bất ngờ phát động sát chiêu.","detail":"Chuông lớn màu vàng chỉ là vật dẫn bên ngoài, còn Kim Ô do bảo thuật diễn hóa được thai nghén và che giấu bên trong. Khi thân chuông bị phá, Kim Ô mới xuất thế để tập kích đối thủ.","nguon":["@c0376"]},{"id":"trung-dong-khai-thien","name":"Trùng Đồng khai thiên","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chưa rõ","hePhai":"Trùng Đồng","soHuu":["Thạch Nghị"],"blurb":"Thần năng Trùng Đồng mở ra một vùng tịnh thổ ngăn cách công kích bên ngoài.","detail":"Thạch Nghị mở một vùng tịnh thổ rộng một trượng giữa tinh hà lôi điện. Trong phạm vi này hoàn toàn yên tĩnh, ánh điện và tiếng động đều không thể xâm nhập.","nguon":["@c0376"]},{"id":"tia-sang-huy-diet-tu-mat-phai-thach-nghi","name":"Tia sáng hủy diệt từ mắt phải của Thạch Nghị","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chưa rõ","hePhai":"Trùng Đồng","soHuu":["Thạch Nghị"],"blurb":"Ánh đen hủy diệt do ký hiệu cổ xưa trong mắt phải Trùng Đồng ngưng tụ và phóng ra.","detail":"Mắt phải đen thẫm của Thạch Nghị bắn ra một tia sáng đen có sức phá hoại thân thể mạnh mẽ. Thạch Hạo tránh được đòn trực diện nhưng chỉ bị sượt qua cũng rách thân thể và chảy nhiều máu.","nguon":["@c0376"]},{"id":"tieu-the-gioi-trung-dong","name":"Tiểu thế giới Trùng Đồng","cn":"","loai":"than-thong","loaiLabel":"Thần thông không gian","phamCap":"","hePhai":"Trùng Đồng","soHuu":["Thạch Nghị"],"blurb":"Thần thông kiến tạo một tiểu thế giới hoang vu rồi thu nhỏ thành lao ngục để trấn phong đối thủ.","detail":"Thạch Nghị dùng sức mạnh Trùng Đồng dựng nên không gian tối tăm có phế tích và khí hỗn độn, kéo Thạch Hạo vào trong rồi thu nhỏ toàn bộ không gian nhằm giam giữ và luyện hóa. Tiểu thế giới sau đó bị bảo thuật Côn Bằng phá nổ.","nguon":["@c0377"]},{"id":"hai-khi-am-duong-trung-dong","name":"Hai khí âm dương Trùng Đồng","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Trùng Đồng","soHuu":["Thạch Nghị"],"blurb":"Hai luồng sức mạnh hủy diệt và sáng tạo được phát ra từ đôi mắt Trùng Đồng.","detail":"Mắt phải của Thạch Nghị phóng ánh sáng đen mang sức hủy diệt, còn mắt trái phóng ánh sáng trắng mang sức sáng tạo. Hai khí âm dương quấn quanh Thạch Hạo và xung kích thập đại Động Thiên; các Tôn giả nhận định uy lực này có thể chém bá chủ khi giao chiến đồng cấp.","nguon":["@c0377"]},{"id":"chien-mau-mau-vang-cua-trung-dong","name":"Chiến mâu màu vàng của Trùng Đồng","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Trùng Đồng","soHuu":["Thạch Nghị"],"blurb":"Phù văn cơ bản của Trùng Đồng hóa thành hai chiến mâu vàng có khả năng xuyên thủng và kích nổ.","detail":"Thạch Nghị phóng hai chiến mâu màu vàng từ Trùng Đồng, xuyên thủng cánh tay trái và ngực Thạch Hạo. Hắn tiếp tục dùng phù văn khống chế hai chiến mâu, định kích nổ chúng để tiêu diệt đối thủ.","nguon":["@c0377"]},{"id":"thap-dai-dong-thien-cua-thach-nghi","name":"Thập đại Động Thiên của Thạch Nghị","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Mười Động Thiên","hePhai":"Động Thiên dị tượng","soHuu":["Thạch Nghị"],"blurb":"Mười Động Thiên mang hình thái mười sinh linh thái cổ chí hung, giúp thần uy của Thạch Nghị tăng mạnh.","detail":"Thạch Nghị triệu ra mười Động Thiên mang hình thái các sinh linh thái cổ chí hung. Quy mô của chúng kém thập đại Động Thiên hợp nhất của Thạch Hạo nhưng vẫn tạo nên uy thế đáng sợ trong cuộc quyết chiến.","nguon":["@c0378"]},{"id":"than-quyen-dai-bang","name":"Thần quyền Đại Bàng","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Bảo thuật Đại Bàng","soHuu":["Thạch Nghị"],"blurb":"Quyền pháp công phạt được Thạch Nghị thi triển bằng tay phải trong thế tiến công tổng hợp.","detail":"Thạch Nghị dùng tay phải hóa thành thần quyền Đại Bàng, đồng thời phối hợp Kỳ Lân ấn ở tay trái và cánh Kim Ô sau lưng để công kích Thạch Hạo.","nguon":["@c0378"]},{"id":"ky-lan-an","name":"Kỳ Lân ấn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Bảo thuật Kỳ Lân","soHuu":["Thạch Nghị"],"blurb":"Ấn pháp công phạt được Thạch Nghị kết bằng tay trái khi triển khai nhiều bảo thuật cùng lúc.","detail":"Kỳ Lân ấn được Thạch Nghị phối hợp với thần quyền Đại Bàng và cánh Kim Ô, tạo thành thế công tổng hợp nhằm áp chế Thạch Hạo.","nguon":["@c0378"]},{"id":"thuong-thuong-kiep-quang","name":"Thượng Thương kiếp quang","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Chí Tôn cốt","soHuu":["Thạch Nghị"],"blurb":"Thần thông phát sinh từ Chí Tôn cốt trong ngực Thạch Nghị, mang uy lực tương tự kiếp phạt đáng sợ được ghi trong sách cổ.","detail":"Vô số tia sáng do ký hiệu hợp thành bao phủ chiến trường, mang sức phá diệt mạnh mẽ và có thể áp chế phạm vi giao chiến. Thạch Nghị thi triển sức mạnh này nhằm hủy diệt Thạch Hạo, nhưng Thạch Hạo vẫn đứng bất diệt giữa kiếp quang.","nguon":["@c0379"]},{"id":"ao-nghia-chi-cao-cua-trung-dong","name":"Áo nghĩa chí cao của Trùng Đồng","cn":"","loai":"than-thong","loaiLabel":"Thần thông thiên phú","phamCap":"","hePhai":"Trùng Đồng","soHuu":["Thạch Nghị"],"blurb":"Lá bài tẩy lớn nhất của Thạch Nghị, dùng để phát huy thần uy cao nhất của Trùng Đồng.","detail":"Khi vận chuyển, đôi mắt có thể hiện ra dị tượng thiên nhật, đại tinh trụy lạc và cảnh vạn vật tạo hóa. Thạch Nghị nhiều lần muốn thi triển nhưng thân thể, tinh khí và thần lực đều đã suy kiệt; cưỡng ép vận dụng trong lúc trọng thương còn khiến hai mắt chảy máu nên áo nghĩa không được triển khai trọn vẹn.","nguon":["@c0380"]},{"id":"bi-luc-chi-ton-cot-trung-sinh","name":"Bí lực Chí Tôn cốt trùng sinh","cn":"","loai":"than-thong","loaiLabel":"Thần thông thiên phú","phamCap":"","hePhai":"Chí Tôn cốt","soHuu":["Thạch Hạo"],"blurb":"Bí lực phát sinh từ Chí Tôn cốt tái sinh của Thạch Hạo, có khả năng khắc chế khối Chí Tôn cốt cũ, hộ thể và giam cầm đối thủ.","detail":"Khi được kích phát, Chí Tôn cốt tái sinh phát ra ký hiệu và tiếng tụng kinh, đồng thời hiện lên người tí hon màu vàng ngồi xếp bằng. Sức mạnh này áp chế khối cốt từng bị lấy khỏi Thạch Hạo, nghiền nứt thân thể Thạch Nghị, ngăn cản lông nhện vàng ám sát và tỏa thần uy cố định đối thủ.","nguon":["@c0380"]},{"id":"don-phan-kich-cua-mat-trung-dong","name":"Đòn phản kích của mắt Trùng Đồng","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chưa rõ","hePhai":"Trùng Đồng","soHuu":["Thạch Nghị"],"blurb":"Đòn phản kích cuối cùng phát ra từ con mắt còn sót lại của Thạch Nghị sau khi hắn tử trận, đủ sức xuyên thủng thân thể Thạch Hạo.","detail":"Con mắt còn sót lại hóa thành điện quang lao thẳng về phía Thạch Hạo rồi nổ tung, giải phóng ký hiệu và mưa sáng. Đòn đánh xuyên thủng thân thể cường đại của Thạch Hạo, để lại lỗ máu và khiến thương thế của nó thêm nghiêm trọng.","nguon":["@c0381"]},{"id":"sau-loai-bao-thuat-cua-chang-trai-trong-lua-than","name":"Sáu loại bảo thuật của chàng trai trong lửa thần","cn":"","loai":"than-thong","loaiLabel":"Bảo thuật","phamCap":"Chưa rõ","hePhai":"Chưa rõ","soHuu":["Chàng trai bên trong lửa thần"],"blurb":"Sáu loại bảo thuật được thi triển đồng thời, xoay chuyển như lục đạo luân hồi để công kích Nguyệt Thiền.","detail":"Chàng trai bên trong lửa thần đồng thời vận dụng sáu loại bảo thuật, tạo thành uy thế dữ dội như lục đạo luân hồi. Bão táp do chúng gây ra khiến nhiều người quan chiến không chịu nổi và bị đẩy bay ngược.","nguon":["@c0382"]},{"id":"anh-do-tu-than-nhan","name":"Ánh đỏ từ thần nhãn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chưa rõ","hePhai":"Chưa rõ","soHuu":["Chàng trai bên trong lửa thần"],"blurb":"Thần thông phóng ký hiệu và ánh đỏ từ mắt, có thể xuyên thủng bảo cụ rồi diệt sát mục tiêu.","detail":"Chàng trai bên trong lửa thần dùng ánh đỏ từ mắt phá hủy nhiều bảo cụ thành tro tàn. Những người trẻ tuổi trúng đòn bị tiêu diệt đến mức hình thần đều diệt.","nguon":["@c0382"]},{"id":"sau-thuat-hop-nhat","name":"Sáu thuật hợp nhất","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chưa rõ","hePhai":"Chưa rõ","soHuu":["Chàng trai thần bí trong lửa thần"],"blurb":"Phương thức đồng thời hợp nhất sáu loại thần thông, biến chúng thành sáu tiểu thế giới xoay tròn để công phạt đối thủ.","detail":"Sáu thần thông được vận chuyển cùng lúc và hóa thành sáu tiểu thế giới, tạo thành thế công đủ sức ép Nguyệt Thiền tiên tử phải vận dụng thần kiếm trong cơ thể cùng áo nghĩa phức tạp nhất của Bổ Thiên giáo. Cách hợp nhất này rất nguy hiểm, chỉ một sai lệch nhỏ cũng có thể khiến kết cấu tan vỡ và đe dọa chính người thi triển.","nguon":["@c0383"]},{"id":"ao-nghia-bo-thien-giao","name":"Áo nghĩa Bổ Thiên giáo","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Áo nghĩa phức tạp nhất của Bổ Thiên giáo","hePhai":"Bổ Thiên giáo","soHuu":["Nguyệt Thiền tiên tử"],"blurb":"Áo nghĩa cao thâm của Bổ Thiên giáo được Nguyệt Thiền tiên tử vận dụng để đối kháng sáu tiểu thế giới.","detail":"Khi bị Sáu thuật hợp nhất áp chế, Nguyệt Thiền tiên tử thi triển áo nghĩa phức tạp nhất của Bổ Thiên giáo, phối hợp với thần kiếm trong cơ thể để chống lại thế công của chàng trai thần bí trong lửa thần.","nguon":["@c0383"]},{"id":"nguyen-rua-manh-nhat-cua-chung-lao","name":"Nguyền rủa mạnh nhất của Chung lão","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật nguyền rủa","phamCap":"Chưa rõ","hePhai":"Bổ Thiên giáo","soHuu":["Chung lão"],"blurb":"Thuật nguyền rủa được Tích Hoa bà bà yêu cầu Chung lão chuẩn bị để ám sát Thạch Hạo giữa lúc hỗn loạn.","detail":"Tích Hoa bà bà ra lệnh cho Chung lão vận dụng nguyền rủa mạnh nhất, nhắm tới việc giết Thạch Hạo bằng một đòn khi nó đang trọng thương. Trong chương này, Chung lão mới chuẩn bị thực hiện và chưa chính thức tung thuật.","nguon":["@c0383"]},{"id":"thu-doan-te-luyen-mau-kim-chu","name":"Thủ đoạn tế luyện máu Kim Chu","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Kim Chu"],"blurb":"Bí thuật dung hợp máu đã tế luyện với sương độc thi thượng cổ, tạo thành tơ nhện sương máu có sức ăn mòn mạnh.","detail":"Kim Chu dùng phù văn kết hợp máu đã tế luyện và sương độc thi thượng cổ để tạo tơ nhện màu máu. Tơ độc có thể làm bảo cụ mục nát và đủ sức uy hiếp sinh linh cấp Tôn giả.","nguon":["@c0384"]},{"id":"bat-chu-tran","name":"Bát Chu trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Hung trận","hePhai":"Hồ Ma Linh nhất mạch","soHuu":["Kim Chu"],"blurb":"Hung trận của hồ Ma Linh nhất mạch, còn được gọi là Bát Quái Kim Chu trận, dùng mạng nhện vàng và tám ký hiệu để phong tỏa thiên địa.","detail":"Kim Chu triển khai trận pháp bằng tám chùm sáng, mạng nhện vàng, tám ký hiệu cùng xích thần trật tự để vây giết mục tiêu. Phiên bản được thi triển mang trận hồn của cổ trận thời thượng cổ từng vây giết thần linh.","nguon":["@c0384"]},{"id":"phap-mon-te-song-bang-thap-dai-dong-thien","name":"Pháp môn tế sống bằng thập đại Động Thiên","cn":"","loai":"bi-thuat","loaiLabel":"Pháp môn","phamCap":"Không rõ","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Pháp môn dùng thập đại Động Thiên cưỡng ép Động Thiên của đối thủ cộng hưởng, thiêu đốt tế phẩm và thu lấy tinh hoa thần tính.","detail":"Thạch Hạo suy diễn con đường này từ lần ngộ đạo và diễn biến thập đại Động Thiên dưới Liễu Thần. Khi thi triển, mười Động Thiên buộc Động Thiên của đối phương hiện ra và cộng hưởng, khiến đối thủ bị tế sống; thần lực cùng tinh hoa thần tính sau đó được dẫn vào thập đại Động Thiên để tẩm bổ người thi triển. Con đường này từng khiến trời nổi giận và bị xem là mang tội lỗi quá nặng.","nguon":["@c0384"]},{"id":"chi-ton-cot-thuc-tinh","name":"Chí Tôn cốt thức tỉnh","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Năng lực thiên phú của Chí Tôn cốt tự phát thức tỉnh khi Thạch Hạo giao chiến với Thạch Nghị.","detail":"Chí Tôn cốt chưa trưởng thành hoàn toàn vẫn thức tỉnh để chém giết địch thủ, nhưng sức mạnh bộc phát đồng thời xé rách ngực, làm gãy nhiều đoạn xương và gây trọng thương ngược lại Thạch Hạo.","nguon":["@c0385"]},{"id":"nha-lao-chin-chu-co","name":"Nhà lao chín chữ cổ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Tôn giả ẩn trong đám đông"],"blurb":"Bảo thuật dùng chín chữ cổ màu xanh lục đan thành một nhà lao để giam cầm mục tiêu.","detail":"Chín chữ cổ lấp lánh quấn lấy nhau và hình thành nhà lao trấn áp Thạch Hạo. Sau khi nhà lao bị sét hình cầu phá hủy, Thạch Hạo còn trích được một tia đạo ấn để truy tìm người thi triển.","nguon":["@c0385"]},{"id":"tieu-the-gioi-trong-long-ban-tay","name":"Tiểu thế giới trong lòng bàn tay","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Thạch Hạo"],"blurb":"Thần thông diễn hóa tinh không và sét hình cầu ngay trong lòng bàn tay.","detail":"Thạch Hạo dùng tiểu thế giới này bao phủ nhà lao chín chữ cổ, lấy sét hình cầu phá hủy nó rồi đoạt một tia đạo ấn nhằm truy tìm Tôn giả đang ẩn thân thi pháp.","nguon":["@c0385"]},{"id":"suc-manh-nguyen-rua","name":"Sức mạnh nguyền rủa","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"","soHuu":["Các Tôn giả đánh lén"],"blurb":"Sức mạnh thần bí được bí mật thi triển để tập kích trực tiếp vào thần hồn.","detail":"Đòn nguyền rủa khiến hai tai Thạch Hạo ù vang, đầu óc trống rỗng và thần hồn suýt bị chém tan. Tính chất bí mật của đòn đánh khiến mục tiêu khó kịp thời phòng bị.","nguon":["@c0385"]},{"id":"bon-kich-chu-tuoc-thai-co-hop-nhat","name":"Bốn kích Chu Tước thái cổ hợp nhất","cn":"","loai":"than-thong","loaiLabel":"Bảo thuật","phamCap":"","hePhai":"Chu Tước","soHuu":["Thạch Hạo"],"blurb":"Thạch Hạo hợp nhất bốn kích Chu Tước thái cổ thành một quyền hỏa công bá đạo.","detail":"Quyền pháp mang theo sóng lửa, Chu Tước và lửa thần, khiến hư không vặn vẹo khi đánh thẳng vào ô lớn màu đen đang trấn áp Thạch Hạo.","nguon":["@c0386"]},{"id":"chi-ton-thuat-trong-bao-thuat-con-bang","name":"Chí Tôn thuật trong bảo thuật Côn Bằng","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chí Tôn thuật","hePhai":"Côn Bằng","soHuu":["Thạch Hạo"],"blurb":"Thần thông diễn hóa côn ngư đen mang sức mạnh Thái Âm để phá tan công kích.","detail":"Thạch Hạo diễn hóa một con côn ngư đen dài hơn một tấc. Cú vẫy đuôi của côn ngư đánh tan hàng loạt thần quang do các Tôn giả phóng tới cứu viện.","nguon":["@c0386"]}]};
